import { Router } from "express";
import type { Response, NextFunction } from "express";
import type { AuthenticatedRequest } from "../middleware/auth.js";
import { agentChat } from "../services/chat/agentChat.js";
import { loadConversation, loadHistory } from "../services/chat/conversationStore.js";
import { isApplicationDatabaseConfigured } from "../db/applicationDataSource.js";
import { logger } from "../services/logger.js";
import { z } from "zod";

/**
 * Dashboard chat route — Phase 5, task 5.11.
 *
 * Spec: design.md §9.1; D3.1, D3.2.
 *
 * POST /api/chat/messages — send a message, get a reply.
 * GET  /api/chat/conversations/:id — read conversation history.
 * GET  /api/admin/conversations — admin observability (task 5.12).
 *
 * Auth: existing JWT header (cookie auth lands Phase 8).
 * No client-side tool-call interpretation (D3.2).
 */

const router = Router();

type AsyncHandler = (req: AuthenticatedRequest, res: Response, next: NextFunction) => Promise<void>;
function handler(fn: AsyncHandler) {
  return (req: AuthenticatedRequest, res: Response, next: NextFunction) => {
    fn(req, res, next).catch(next);
  };
}

const ChatMessageBodySchema = z.object({
  text: z.string().min(1).max(4000),
  conversationId: z.string().optional(),
});

// ── POST /api/chat/messages ─────────────────────────────────────────────────

router.post(
  "/chat/messages",
  handler(async (req, res) => {
    const userId = res.locals["userId"] as string;
    const parsed = ChatMessageBodySchema.safeParse(req.body);
    if (!parsed.success) {
      res.status(400).json({ error: "invalid_request", details: parsed.error.message });
      return;
    }

    try {
      const result = await agentChat({
        userId,
        text: parsed.data.text,
        channel: "dashboard",
        ...(parsed.data.conversationId ? { conversationId: parsed.data.conversationId } : {}),
      });
      res.json({
        conversationId: result.conversationId,
        replyText: result.replyText,
        terminationReason: result.terminationReason,
        totalCostUsd: result.totalCostUsd,
        turnCount: result.turnCount,
      });
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      logger.error(`chat route error user=${userId}: ${msg}`);
      res.status(500).json({ error: "chat_error", message: "An error occurred processing your message." });
    }
  })
);

// ── GET /api/chat/conversations/:id ─────────────────────────────────────────

router.get(
  "/chat/conversations/:id",
  handler(async (req, res) => {
    const userId = res.locals["userId"] as string;
    const conversationId = String(req.params["id"] ?? "");

    if (!isApplicationDatabaseConfigured()) {
      res.status(503).json({ error: "database_unavailable" });
      return;
    }

    const conv = await loadConversation(conversationId);
    if (!conv || conv.userId !== userId) {
      res.status(404).json({ error: "conversation_not_found" });
      return;
    }

    const turns = await loadHistory(conversationId, 200);
    res.json({ conversation: conv, turns });
  })
);

export default router;

import { getApplicationDataSource, isApplicationDatabaseConfigured } from "../../db/applicationDataSource.js";
import { buildPersonaPrompt, REDIRECT_LINE } from "./personaPrompt.js";
import { filterText } from "./outputFilter.js";
import { buildToolRegistry, ALL_TOOL_NAMES } from "./tools/registry.js";
import * as confirmationStore from "./confirmationStore.js";
import * as conversationStore from "./conversationStore.js";
import { isFeatureEnabled, getFeatureValue } from "../featureFlagService.js";
import { ensurePointsBudgetAvailable } from "../pointsBudgetService.js";
import { resolveStepModel } from "../stepQueue/modelTier.js";
import { getLlmProvider } from "./llmProviders/index.js";
import * as strategyStore from "../strategyStore.js";
import * as reportIndexStore from "../reportIndexStore.js";
import * as escalationHistoryStore from "../escalationHistoryStore.js";
import * as snoozeStore from "../snoozeStore.js";
import * as notificationStore from "../notificationStore.js";
import * as portfolioRiskStore from "../portfolioRiskStore.js";
import * as verdictActionsStore from "../verdictActionsStore.js";
import { logger } from "../logger.js";
import type { ConversationChannel } from "../../db/entities/ConversationEntity.js";

/**
 * agentChat — Phase 5, task 5.9.
 *
 * Spec: design.md §7.1–7.4; C1.1–C1.7, G1.1–G1.4, F2.2, E4.2.
 *
 * Single entry point for all three transports. Channel is used only as an
 * audit field; the loop, prompt, and tool registry are identical (C1.3).
 */

export interface AgentChatInput {
  userId: string;
  text: string;
  channel: ConversationChannel;
  conversationId?: string;
}

export interface AgentChatResult {
  replyText: string;
  conversationId: string;
  terminationReason: "model_final" | "max_turns" | "token_cap" | "points_budget_exhausted" | "error";
  totalCostUsd: number;
  turnCount: number;
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

async function getDisplayName(userId: string): Promise<string> {
  if (!isApplicationDatabaseConfigured()) return userId;
  try {
    const ds = await getApplicationDataSource();
    const rows = await ds.query(
      `SELECT display_name FROM users WHERE user_id = $1 LIMIT 1`,
      [userId]
    ) as Array<{ display_name: string }>;
    return rows[0]?.display_name ?? userId;
  } catch {
    return userId;
  }
}

function extractTextFromContent(content: unknown): string {
  if (typeof content === "string") return content;
  if (Array.isArray(content)) {
    return content
      .filter((b): b is { type: string; text: string } => b && typeof b === "object" && b.type === "text")
      .map((b) => b.text)
      .join("\n");
  }
  return String(content ?? "");
}

/**
 * Parse tool-call blocks from the model's text response.
 * The model is instructed to emit:
 *   ```tool_call
 *   {"name": "...", "id": "...", "input": {...}}
 *   ```
 * We also handle native tool_use blocks from providers that support them.
 */
function extractToolUseBlocks(content: unknown): Array<{ id: string; name: string; input: unknown }> {
  const blocks: Array<{ id: string; name: string; input: unknown }> = [];

  // 1. Native tool_use blocks (Anthropic-style, for future native providers)
  if (Array.isArray(content)) {
    for (const b of content) {
      if (b && typeof b === "object" && b.type === "tool_use" && typeof b.name === "string") {
        blocks.push({ id: String(b.id ?? `tool_${Date.now()}`), name: b.name, input: b.input ?? {} });
      }
    }
    if (blocks.length > 0) return blocks;
  }

  // 2. Text-based tool_call blocks (OpenRouter text response)
  const text = extractTextFromContent(content);
  const TOOL_CALL_RE = /```tool_call\s*\n([\s\S]*?)\n```/g;
  let match: RegExpExecArray | null;
  while ((match = TOOL_CALL_RE.exec(text)) !== null) {
    try {
      const parsed = JSON.parse(match[1]!) as { name?: string; id?: string; input?: unknown };
      if (typeof parsed.name === "string") {
        blocks.push({
          id: typeof parsed.id === "string" ? parsed.id : `tool_${Date.now()}_${blocks.length}`,
          name: parsed.name,
          input: parsed.input ?? {},
        });
      }
    } catch {
      // malformed JSON in tool_call block — skip
    }
  }
  return blocks;
}

// ---------------------------------------------------------------------------
// Main function
// ---------------------------------------------------------------------------

export async function agentChat(input: AgentChatInput): Promise<AgentChatResult> {
  const { userId, text, channel } = input;

  // Feature gate (F3.1 — startup guard also enforces this)
  const enabled = await isFeatureEnabled("chat_agent_enabled", userId);
  if (!enabled) {
    return {
      replyText: REDIRECT_LINE,
      conversationId: input.conversationId ?? `conv_disabled_${Date.now()}`,
      terminationReason: "error",
      totalCostUsd: 0,
      turnCount: 0,
    };
  }

  // Budget gate (NFR2.2)
  const budget = await ensurePointsBudgetAvailable(userId);
  if (!budget.allowed) {
    const convId = input.conversationId ?? `conv_budget_${Date.now()}`;
    return {
      replyText: "Your daily budget is exhausted. Try again after the budget window resets.",
      conversationId: convId,
      terminationReason: "points_budget_exhausted",
      totalCostUsd: 0,
      turnCount: 0,
    };
  }

  // Resolve or create conversation
  let conv = input.conversationId
    ? await conversationStore.loadConversation(input.conversationId)
    : null;
  if (!conv) {
    conv = await conversationStore.createConversation({ userId, channel });
  }
  const conversationId = conv.id;

  // Append user turn
  await conversationStore.appendTurn(conversationId, { role: "user", content: text });

  // Confirmation handshake check (§7.4)
  const pending = confirmationStore.peek(conversationId);
  if (pending) {
    const decision = confirmationStore.parseConfirmation(text);
    if (decision === "deny") {
      confirmationStore.clear(conversationId);
      const reply = "Cancelled. What else can I help with?";
      await conversationStore.appendTurn(conversationId, { role: "assistant", content: reply });
      await conversationStore.endConversation(conversationId, "model_final");
      return { replyText: reply, conversationId, terminationReason: "model_final", totalCostUsd: 0, turnCount: conv.turnCount + 2 };
    }
    if (decision === "confirm") {
      // Will be handled in the tool dispatch below with confirmationToken set
    }
    // "unclear" — let the model handle it; clear the pending
    if (decision === "unclear") {
      confirmationStore.clear(conversationId);
    }
  }

  // Resolve model
  const maxTurns = await getFeatureValue<number>("max_turns") ?? 12;
  const tokenCap = await getFeatureValue<number>("conversation_token_cap") ?? 120_000;
  const displayName = await getDisplayName(userId);
  const persona = buildPersonaPrompt(displayName);

  let resolvedModel: Awaited<ReturnType<typeof resolveStepModel>> | null = null;
  if (isApplicationDatabaseConfigured()) {
    try {
      const ds = await getApplicationDataSource();
      const userTierRows = await ds.query(
        `SELECT model_tier FROM users WHERE user_id = $1 LIMIT 1`,
        [userId]
      ) as Array<{ model_tier: string }>;
      const tier = (userTierRows[0]?.model_tier ?? "balanced") as "free" | "cheap" | "balanced" | "expensive";
      resolvedModel = await resolveStepModel(ds, userId, "chat_agent", tier);
    } catch {
      // Fall through to default
    }
  }
  const modelName = resolvedModel?.primary ?? "google/gemini-2.5-flash";
  const providerName = resolvedModel?.provider ?? "openrouter";
  const provider = getLlmProvider(providerName as "openrouter" | "anthropic" | "openai" | "gemini");

  // Build tool registry
  const db = isApplicationDatabaseConfigured() ? await getApplicationDataSource() : null;
  const toolCtx = {
    userId,
    conversationId,
    turnIndex: conv.turnCount,
    confirmationToken: pending && confirmationStore.parseConfirmation(text) === "confirm" ? pending.toolUseId : null,
    db,
    strategyStore,
    reportIndexStore,
    escalationHistoryStore,
    snoozeStore,
    notificationStore,
    portfolioRiskStore,
    verdictActionsStore,
  };
  const tools = buildToolRegistry(toolCtx);
  // Build the tool manifest to embed in the system prompt.
  // OpenRouter supports native tool calling for Claude models via the `tools`
  // parameter, but the current OpenRouterProvider uses the chat completions
  // endpoint without tool_use. We embed the tool list as structured JSON in
  // the system prompt so the model knows what tools are available and can
  // request them by name in its response. The agentChat loop then parses
  // the model's text output for tool-call requests.
  //
  // This is the Phase 5 approach. Phase 5 Anthropic/OpenAI/Gemini providers
  // will use native tool calling once implemented.
  const toolManifestJson = JSON.stringify(
    tools.map((t) => ({
      name: t.name,
      category: t.category,
      description: t.description,
      parameters: t.inputSchema,
      ...(t.costPoints !== undefined ? { costPoints: t.costPoints } : {}),
      ...(t.requiresConfirmation ? { requiresConfirmation: true } : {}),
    })),
    null,
    2
  );
  const personaWithTools = `${persona}

## Available tools

You have access to the following tools. To call a tool, respond with a JSON block in this exact format:
\`\`\`tool_call
{"name": "<tool_name>", "id": "<unique_id>", "input": {<args>}}
\`\`\`

Rules:
- For READ tools: call them freely whenever you need data.
- For ACTION tools (requiresConfirmation=true): emit the tool_call block immediately when the user requests the action. Do NOT ask "should I proceed?" — the system handles confirmation.
- After calling a tool, wait for the tool result before continuing.
- Only call tools that are listed below.

${toolManifestJson}`;

  // Load history
  const history = await conversationStore.loadHistory(conversationId, maxTurns * 2);
  const messages: Array<{ role: "user" | "assistant"; content: string }> = history
    .filter((t) => t.role === "user" || t.role === "assistant")
    .map((t) => ({ role: t.role as "user" | "assistant", content: extractTextFromContent(t.content) }));

  let totalCost = 0;
  let totalTokens = 0;
  let turnIndex = conv.turnCount + 1;
  let loopCount = 0;

  // Tool-calling loop
  while (true) {
    loopCount += 1;
    if (loopCount > maxTurns) {
      const reply = "I have to stop here for now (turn limit reached).";
      await conversationStore.appendTurn(conversationId, { role: "assistant", content: reply });
      await conversationStore.endConversation(conversationId, "max_turns", modelName);
      return { replyText: reply, conversationId, terminationReason: "max_turns", totalCostUsd: totalCost, turnCount: turnIndex };
    }
    if (totalTokens >= tokenCap) {
      const reply = "I had to stop here — the conversation reached its token limit.";
      await conversationStore.appendTurn(conversationId, { role: "assistant", content: reply });
      await conversationStore.endConversation(conversationId, "token_cap", modelName);
      return { replyText: reply, conversationId, terminationReason: "token_cap", totalCostUsd: totalCost, turnCount: turnIndex };
    }

    const t0 = Date.now();
    let resp: Awaited<ReturnType<typeof provider.invoke>>;
    try {
      resp = await provider.invoke({
        model: modelName,
        messages: [
          { role: "system", content: personaWithTools },
          ...messages,
        ],
      });
    } catch (err) {
      logger.warn(`agentChat: provider error user=${userId} conv=${conversationId}: ${(err as Error).message}`);
      const reply = "I encountered an error. Please try again.";
      await conversationStore.appendTurn(conversationId, { role: "assistant", content: reply });
      await conversationStore.endConversation(conversationId, "error", modelName);
      return { replyText: reply, conversationId, terminationReason: "error", totalCostUsd: totalCost, turnCount: turnIndex };
    }

    totalCost += resp.usage.costUsd;
    totalTokens += resp.usage.tokensIn + resp.usage.tokensOut;

    const rawContent = resp.content;
    const textContent = extractTextFromContent(rawContent);
    const toolUseBlocks = extractToolUseBlocks(rawContent);

    await conversationStore.appendTurn(conversationId, {
      role: "assistant",
      content: rawContent,
      model: resp.model,
      tokensIn: resp.usage.tokensIn,
      tokensOut: resp.usage.tokensOut,
      costUsd: resp.usage.costUsd,
      latencyMs: Date.now() - t0,
    });
    turnIndex += 1;
    messages.push({ role: "assistant", content: textContent });

    // No tool calls → final answer
    if (toolUseBlocks.length === 0) {
      // Strip any tool_call blocks from the final text before showing to user
      const cleanText = textContent.replace(/```tool_call[\s\S]*?```/g, "").trim();
      const filtered = await filterText(cleanText || textContent, {
        conversationId,
        turnIndex: turnIndex - 1,
        site: "final_reply",
      });
      await conversationStore.endConversation(conversationId, "model_final", modelName);
      return {
        replyText: filtered.text,
        conversationId,
        terminationReason: "model_final",
        totalCostUsd: totalCost,
        turnCount: turnIndex,
      };
    }

    // Dispatch tool calls
    const toolResults: string[] = [];
    for (const block of toolUseBlocks) {
      // E4.2: refuse unregistered tools
      if (!(ALL_TOOL_NAMES as readonly string[]).includes(block.name)) {
        logger.warn(`agentChat: refused unregistered tool ${block.name} user=${userId}`);
        if (db) {
          await db.query(
            `INSERT INTO tool_calls
               (id, conversation_id, turn_index, tool_name, category, args_json,
                result_status, result_latency_ms, cost_points, audit_note, occurred_at)
             VALUES (gen_random_uuid(), $1, $2, $3, 'read', '{}'::jsonb, 'rejected', 0, 0, 'tool_not_registered', NOW())`,
            [conversationId, turnIndex - 1, block.name.slice(0, 64)]
          );
        }
        toolResults.push(`Tool "${block.name}" is not available.`);
        continue;
      }

      const tool = tools.find((t) => t.name === block.name);
      if (!tool) {
        toolResults.push(`Tool "${block.name}" is not available.`);
        continue;
      }

      // Action tool confirmation gate (E2.2)
      if (tool.category === "action" && tool.requiresConfirmation !== false) {
        const hasPendingConfirmation = pending && confirmationStore.parseConfirmation(text) === "confirm";
        if (!hasPendingConfirmation) {
          // Propose the action and exit the loop
          const summary = `${tool.name}(${JSON.stringify(block.input)})`;
          const reply = `I'd like to run: **${summary}**. Reply 'yes' to confirm, or 'no' to skip.`;
          confirmationStore.put(conversationId, {
            toolUseId: block.id,
            toolName: tool.name,
            args: block.input,
            createdAt: Date.now(),
          });
          await conversationStore.appendTurn(conversationId, { role: "assistant", content: reply });
          await conversationStore.endConversation(conversationId, "model_final", modelName);
          return { replyText: reply, conversationId, terminationReason: "model_final", totalCostUsd: totalCost, turnCount: turnIndex };
        }
        // Confirmed — clear the pending and execute
        confirmationStore.clear(conversationId);
      }

      const result = await tool.handler(block.input, {
        ...toolCtx,
        turnIndex: turnIndex - 1,
        confirmationToken: pending?.toolUseId ?? null,
      });
      await conversationStore.incrementToolCallCount(conversationId);

      // Filter tool result (F2.2)
      const resultText = JSON.stringify(result);
      const filtered = await filterText(resultText, {
        conversationId,
        turnIndex: turnIndex - 1,
        site: "tool_result",
      });
      toolResults.push(`${tool.name}: ${filtered.text}`);
    }

    // Feed tool results back as a user message for the next loop iteration
    if (toolResults.length > 0) {
      const toolResultContent = toolResults.join("\n\n");
      messages.push({ role: "user", content: `Tool results:\n${toolResultContent}` });
      await conversationStore.appendTurn(conversationId, {
        role: "tool_result",
        content: toolResults,
      });
      turnIndex += 1;
    }
  }
}

import { randomUUID } from "crypto";
import { getApplicationDataSource, isApplicationDatabaseConfigured } from "../../db/applicationDataSource.js";
import type { ConversationChannel, ConversationTerminationReason } from "../../db/entities/ConversationEntity.js";
import type { TurnRole } from "../../db/entities/ConversationTurnEntity.js";
import { getFeatureValue } from "../featureFlagService.js";
import { unwrapMutationRows } from "../dbUtils.js";

/**
 * Conversation store — Phase 5, task 5.8; saved-chat lifecycle extended in M001/S04.
 *
 * Spec: design.md §4.11; C2.1, C2.2, C2.3, NFR6.2, NFR6.4.
 *
 * Persists every conversation turn, tool call, and conversation summary.
 * `appendToolCall` writes the audit row BEFORE the handler executes (NFR6.4).
 */

const DEFAULT_SAVED_CHAT_TTL_DAYS = 7;
const MAX_SAVED_CHAT_TITLE_LENGTH = 160;

type ConversationStoreErrorCode =
  | "DATABASE_UNAVAILABLE"
  | "DATABASE_ERROR"
  | "INVALID_TITLE"
  | "INVALID_CONVERSATION_ID"
  | "CONVERSATION_NOT_FOUND"
  | "MALFORMED_ROW";

export class ConversationStoreError extends Error {
  constructor(readonly code: ConversationStoreErrorCode, message: string, options?: { cause?: unknown }) {
    super(`conversation_store_${code}: ${message}`, options);
    this.name = "ConversationStoreError";
  }
}

interface QueryRunnerLike {
  query<T = unknown>(sql: string, params: unknown[]): Promise<T>;
}

interface DataSourceLike extends QueryRunnerLike {
  transaction<T>(run: (manager: QueryRunnerLike) => Promise<T>): Promise<T>;
}

export interface ConversationStoreDeps {
  databaseConfigured: () => boolean;
  dataSourceProvider: () => Promise<DataSourceLike>;
  featureValueProvider: <T>(name: string, userId?: string) => Promise<T | undefined>;
  now: () => Date;
  idFactory: () => string;
}

const defaultDeps: ConversationStoreDeps = {
  databaseConfigured: isApplicationDatabaseConfigured,
  dataSourceProvider: async () => getApplicationDataSource() as unknown as DataSourceLike,
  featureValueProvider: getFeatureValue,
  now: () => new Date(),
  idFactory: () => `conv_${Date.now()}_${randomUUID().slice(0, 8)}`,
};

export interface ConversationRecord {
  id: string;
  userId: string;
  channel: ConversationChannel;
  title: string | null;
  startedAt: string;
  updatedAt: string;
  lastActivityAt: string;
  archivedAt: string | null;
  expiresAt: string | null;
  endedAt: string | null;
  turnCount: number;
  totalTokensIn: number;
  totalTokensOut: number;
  totalCostUsd: number;
  terminationReason: ConversationTerminationReason | null;
  toolCallCount: number;
  model: string | null;
}

export type SavedConversationMetadata = ConversationRecord;
export type SavedConversationAccessState = "active" | "archived" | "expired";

export interface SavedConversationLoadResult extends SavedConversationMetadata {
  accessState: SavedConversationAccessState;
  isArchived: boolean;
  isExpired: boolean;
}

export interface TurnRecord {
  conversationId: string;
  turnIndex: number;
  role: TurnRole;
  content: unknown;
  model: string | null;
  tokensIn: number;
  tokensOut: number;
  costUsd: number;
  latencyMs: number;
  createdAt: string;
}

export interface AppendTurnInput {
  role: TurnRole;
  content: unknown;
  model?: string | null;
  tokensIn?: number;
  tokensOut?: number;
  costUsd?: number;
  latencyMs?: number;
}

// ---------------------------------------------------------------------------
// Saved-chat lifecycle
// ---------------------------------------------------------------------------

export async function createSavedConversation(
  input: {
    userId: string;
    title?: string | null;
    model?: string | null;
    ttlDays?: number;
  },
  deps: ConversationStoreDeps = defaultDeps
): Promise<SavedConversationMetadata> {
  return withStoreErrors("createSavedConversation", async () => {
    const ds = await requireDataSource(deps);
    const ttlDays = input.ttlDays ?? coerceTtlDays(
      await deps.featureValueProvider<unknown>("chat_conversation_ttl_days", input.userId)
    );
    const expiresAt = addDays(deps.now(), coerceTtlDays(ttlDays));
    const title = normalizeOptionalTitle(input.title);
    const rows = await ds.query(
      `INSERT INTO conversations
         (id, user_id, channel, started_at, updated_at, turn_count, total_tokens_in, total_tokens_out,
          total_cost_usd, tool_call_count, model, title, expires_at)
       VALUES ($1, $2, $3, NOW(), NOW(), 0, 0, 0, 0, 0, $4, $5, $6)
       RETURNING ${conversationSelectColumns()}`,
      [deps.idFactory(), input.userId, "dashboard", input.model ?? null, title, expiresAt]
    ) as Array<Record<string, unknown>>;
    return fromSavedConversationRow(rows[0]);
  });
}

export async function listSavedDashboardConversations(
  userId: string,
  deps: ConversationStoreDeps = defaultDeps
): Promise<SavedConversationMetadata[]> {
  return withStoreErrors("listSavedDashboardConversations", async () => {
    const ds = await requireDataSource(deps);
    const rows = await ds.query(
      `SELECT ${conversationSelectColumns()}
         FROM conversations
        WHERE user_id = $1
          AND channel = 'dashboard'
          AND archived_at IS NULL
        ORDER BY updated_at DESC, started_at DESC`,
      [userId]
    ) as Array<Record<string, unknown>>;
    return rows.map(fromSavedConversationRow);
  });
}

export async function loadConversationForUser(
  input: { userId: string; conversationId: string },
  deps: ConversationStoreDeps = defaultDeps
): Promise<SavedConversationLoadResult | null> {
  return withStoreErrors("loadConversationForUser", async () => {
    const conversationId = normalizeConversationId(input.conversationId);
    const ds = await requireDataSource(deps);
    const rows = await ds.query(
      `SELECT ${conversationSelectColumns()}
         FROM conversations
        WHERE id = $1 AND user_id = $2
        LIMIT 1`,
      [conversationId, input.userId]
    ) as Array<Record<string, unknown>>;
    if (!rows[0]) return null;
    return withAccessState(fromSavedConversationRow(rows[0]), deps.now());
  });
}

export async function renameSavedConversation(
  input: { userId: string; conversationId: string; title: string },
  deps: ConversationStoreDeps = defaultDeps
): Promise<SavedConversationMetadata> {
  return withStoreErrors("renameSavedConversation", async () => {
    const title = normalizeRequiredTitle(input.title);
    const conversationId = normalizeConversationId(input.conversationId);
    const ds = await requireDataSource(deps);
    const rawRows = await ds.query(
      `UPDATE conversations
          SET title = $1,
              updated_at = NOW()
        WHERE id = $2 AND user_id = $3
          AND channel = 'dashboard'
          AND archived_at IS NULL
       RETURNING ${conversationSelectColumns()}`,
      [title, conversationId, input.userId]
    );
    const rows = unwrapMutationRows<Record<string, unknown>>(rawRows);
    if (rows.length === 0) {
      throw new ConversationStoreError("CONVERSATION_NOT_FOUND", "conversation was not found for user");
    }
    return fromSavedConversationRow(rows[0]);
  });
}

export async function archiveSavedConversation(
  input: { userId: string; conversationId: string },
  deps: ConversationStoreDeps = defaultDeps
): Promise<SavedConversationMetadata> {
  return withStoreErrors("archiveSavedConversation", async () => {
    const conversationId = normalizeConversationId(input.conversationId);
    const ds = await requireDataSource(deps);
    const rawRows = await ds.query(
      `UPDATE conversations
          SET archived_at = COALESCE(archived_at, NOW()),
              updated_at = NOW()
        WHERE id = $1 AND user_id = $2
          AND channel = 'dashboard'
       RETURNING ${conversationSelectColumns()}`,
      [conversationId, input.userId]
    );
    const rows = unwrapMutationRows<Record<string, unknown>>(rawRows);
    if (rows.length === 0) {
      throw new ConversationStoreError("CONVERSATION_NOT_FOUND", "conversation was not found for user");
    }
    return fromSavedConversationRow(rows[0]);
  });
}

// ---------------------------------------------------------------------------
// Create / load
// ---------------------------------------------------------------------------

export async function createConversation(input: {
  userId: string;
  channel: ConversationChannel;
  model?: string | null;
  title?: string | null;
  expiresAt?: Date | null;
}): Promise<ConversationRecord> {
  if (!isApplicationDatabaseConfigured()) {
    throw new Error("createConversation requires the application database");
  }
  const ds = await getApplicationDataSource();
  const id = `conv_${Date.now()}_${randomUUID().slice(0, 8)}`;
  const rows = await ds.query(
    `INSERT INTO conversations
       (id, user_id, channel, started_at, updated_at, turn_count, total_tokens_in, total_tokens_out,
        total_cost_usd, tool_call_count, model, title, expires_at)
     VALUES ($1, $2, $3, NOW(), NOW(), 0, 0, 0, 0, 0, $4, $5, $6)
     RETURNING ${conversationSelectColumns()}`,
    [id, input.userId, input.channel, input.model ?? null, normalizeOptionalTitle(input.title), input.expiresAt ?? null]
  ) as Array<Record<string, unknown>>;
  return fromRow(rows[0]!);
}

export async function loadConversation(conversationId: string): Promise<ConversationRecord | null> {
  if (!isApplicationDatabaseConfigured()) return null;
  const ds = await getApplicationDataSource();
  const rows = await ds.query(
    `SELECT ${conversationSelectColumns()}
       FROM conversations WHERE id = $1 LIMIT 1`,
    [conversationId]
  ) as Array<Record<string, unknown>>;
  return rows[0] ? fromRow(rows[0]) : null;
}

// ---------------------------------------------------------------------------
// Turn management
// ---------------------------------------------------------------------------

export async function appendTurn(
  conversationId: string,
  input: AppendTurnInput
): Promise<TurnRecord> {
  if (!isApplicationDatabaseConfigured()) {
    throw new Error("appendTurn requires the application database");
  }
  const ds = await getApplicationDataSource();

  return ds.transaction(async (manager) => {
    // Increment turn_count and get the new index atomically.
    // unwrapMutationRows handles TypeORM's [rows, rowCount] UPDATE RETURNING shape.
    const rawUpdated = await manager.query(
      `UPDATE conversations
          SET turn_count = turn_count + 1,
              total_tokens_in = total_tokens_in + $2,
              total_tokens_out = total_tokens_out + $3,
              total_cost_usd = total_cost_usd + $4,
              updated_at = NOW()
        WHERE id = $1
        RETURNING turn_count`,
      [
        conversationId,
        input.tokensIn ?? 0,
        input.tokensOut ?? 0,
        input.costUsd ?? 0,
      ]
    );
    const updatedRows = unwrapMutationRows<{ turn_count: number }>(rawUpdated);
    if (updatedRows.length === 0) {
      throw new Error(`conversation_not_found: ${conversationId}`);
    }
    const turnIndex = updatedRows[0]!.turn_count - 1;

    const rows = await manager.query(
      `INSERT INTO conversation_turns
         (conversation_id, turn_index, role, content, model,
          tokens_in, tokens_out, cost_usd, latency_ms, created_at)
       VALUES ($1, $2, $3, $4::jsonb, $5, $6, $7, $8, $9, NOW())
       RETURNING conversation_id, turn_index, role, content, model,
                 tokens_in, tokens_out, cost_usd, latency_ms, created_at`,
      [
        conversationId,
        turnIndex,
        input.role,
        JSON.stringify(input.content),
        input.model ?? null,
        input.tokensIn ?? 0,
        input.tokensOut ?? 0,
        input.costUsd ?? 0,
        input.latencyMs ?? 0,
      ]
    ) as Array<Record<string, unknown>>;
    return fromTurnRow(rows[0]!);
  });
}

export async function loadHistory(
  conversationId: string,
  maxTurns = 50
): Promise<TurnRecord[]> {
  if (!isApplicationDatabaseConfigured()) return [];
  const ds = await getApplicationDataSource();
  const rows = await ds.query(
    `SELECT conversation_id, turn_index, role, content, model,
            tokens_in, tokens_out, cost_usd, latency_ms, created_at
       FROM conversation_turns
      WHERE conversation_id = $1
      ORDER BY turn_index ASC
      LIMIT $2`,
    [conversationId, maxTurns]
  ) as Array<Record<string, unknown>>;
  return rows.map(fromTurnRow);
}

// ---------------------------------------------------------------------------
// Finalization
// ---------------------------------------------------------------------------

export async function endConversation(
  conversationId: string,
  reason: ConversationTerminationReason,
  model?: string | null
): Promise<void> {
  if (!isApplicationDatabaseConfigured()) return;
  const ds = await getApplicationDataSource();
  await ds.query(
    `UPDATE conversations
        SET ended_at = NOW(),
            updated_at = NOW(),
            termination_reason = $2,
            model = COALESCE($3, model)
      WHERE id = $1`,
    [conversationId, reason, model ?? null]
  );
}

export async function incrementToolCallCount(conversationId: string): Promise<void> {
  if (!isApplicationDatabaseConfigured()) return;
  const ds = await getApplicationDataSource();
  await ds.query(
    `UPDATE conversations SET tool_call_count = tool_call_count + 1, updated_at = NOW() WHERE id = $1`,
    [conversationId]
  );
}

// ---------------------------------------------------------------------------
// Row mappers / helpers
// ---------------------------------------------------------------------------

function conversationSelectColumns(): string {
  return `id, user_id, channel, title, started_at, updated_at, archived_at, expires_at,
          ended_at, turn_count, total_tokens_in, total_tokens_out, total_cost_usd,
          termination_reason, tool_call_count, model`;
}

function normalizeRequiredTitle(title: string): string {
  const normalized = title.trim();
  if (normalized.length === 0) {
    throw new ConversationStoreError("INVALID_TITLE", "saved chat title cannot be blank");
  }
  if (normalized.length > MAX_SAVED_CHAT_TITLE_LENGTH) {
    throw new ConversationStoreError(
      "INVALID_TITLE",
      `saved chat title cannot exceed ${MAX_SAVED_CHAT_TITLE_LENGTH} characters`
    );
  }
  return normalized;
}

function normalizeOptionalTitle(title: string | null | undefined): string | null {
  if (title === null || title === undefined) return null;
  const normalized = title.trim();
  if (normalized.length === 0) return null;
  if (normalized.length > MAX_SAVED_CHAT_TITLE_LENGTH) {
    throw new ConversationStoreError(
      "INVALID_TITLE",
      `saved chat title cannot exceed ${MAX_SAVED_CHAT_TITLE_LENGTH} characters`
    );
  }
  return normalized;
}

function normalizeConversationId(conversationId: string): string {
  const normalized = conversationId.trim();
  if (normalized.length === 0 || normalized.length > 64) {
    throw new ConversationStoreError("INVALID_CONVERSATION_ID", "conversation id is invalid");
  }
  return normalized;
}

function coerceTtlDays(value: unknown): number {
  const numeric = typeof value === "number" ? value : Number(value);
  if (!Number.isFinite(numeric) || numeric < 1) return DEFAULT_SAVED_CHAT_TTL_DAYS;
  return Math.floor(numeric);
}

function addDays(date: Date, days: number): Date {
  const copy = new Date(date.getTime());
  copy.setUTCDate(copy.getUTCDate() + days);
  return copy;
}

async function requireDataSource(deps: ConversationStoreDeps): Promise<DataSourceLike> {
  if (!deps.databaseConfigured()) {
    throw new ConversationStoreError("DATABASE_UNAVAILABLE", "application database is not configured");
  }
  return deps.dataSourceProvider();
}

async function withStoreErrors<T>(operation: string, run: () => Promise<T>): Promise<T> {
  try {
    return await run();
  } catch (error) {
    if (error instanceof ConversationStoreError) throw error;
    throw new ConversationStoreError("DATABASE_ERROR", `${operation} failed`, { cause: error });
  }
}

function fromRow(row: Record<string, unknown>): ConversationRecord {
  return fromSavedConversationRow(row);
}

function fromSavedConversationRow(row: Record<string, unknown> | undefined): SavedConversationMetadata {
  if (!row) {
    throw new ConversationStoreError("MALFORMED_ROW", "conversation row is missing");
  }
  const id = requiredString(row, "id");
  const userId = requiredString(row, "user_id");
  const title = optionalString(row, "title");
  const startedAt = requiredIso(row, "started_at");
  const updatedAt = requiredIso(row, "updated_at");
  return {
    id,
    userId,
    channel: requiredString(row, "channel") as ConversationChannel,
    title,
    startedAt,
    updatedAt,
    lastActivityAt: updatedAt,
    archivedAt: optionalIso(row, "archived_at"),
    expiresAt: optionalIso(row, "expires_at"),
    endedAt: optionalIso(row, "ended_at"),
    turnCount: safeNonNegativeInteger(row["turn_count"]),
    totalTokensIn: safeNonNegativeInteger(row["total_tokens_in"]),
    totalTokensOut: safeNonNegativeInteger(row["total_tokens_out"]),
    totalCostUsd: safeNonNegativeNumber(row["total_cost_usd"]),
    terminationReason: optionalString(row, "termination_reason") as ConversationTerminationReason | null,
    toolCallCount: safeNonNegativeInteger(row["tool_call_count"]),
    model: optionalString(row, "model"),
  };
}

function withAccessState(row: SavedConversationMetadata, now: Date): SavedConversationLoadResult {
  const isArchived = row.archivedAt !== null;
  const isExpired = row.expiresAt !== null && new Date(row.expiresAt).getTime() <= now.getTime();
  const accessState: SavedConversationAccessState = isArchived ? "archived" : isExpired ? "expired" : "active";
  return {
    ...row,
    accessState,
    isArchived,
    isExpired,
  };
}

function requiredString(row: Record<string, unknown>, field: string): string {
  const value = row[field];
  if (typeof value !== "string" || value.trim().length === 0) {
    throw new ConversationStoreError("MALFORMED_ROW", `conversation row field ${field} is invalid`);
  }
  return value;
}

function optionalString(row: Record<string, unknown>, field: string): string | null {
  const value = row[field];
  if (value === null || value === undefined) return null;
  if (typeof value !== "string") {
    throw new ConversationStoreError("MALFORMED_ROW", `conversation row field ${field} is invalid`);
  }
  return value;
}

function requiredIso(row: Record<string, unknown>, field: string): string {
  const iso = optionalIso(row, field);
  if (!iso) {
    throw new ConversationStoreError("MALFORMED_ROW", `conversation row field ${field} is invalid`);
  }
  return iso;
}

function optionalIso(row: Record<string, unknown>, field: string): string | null {
  const value = row[field];
  if (value === null || value === undefined) return null;
  const date = value instanceof Date ? value : typeof value === "string" ? new Date(value) : null;
  if (!date || Number.isNaN(date.getTime())) {
    throw new ConversationStoreError("MALFORMED_ROW", `conversation row field ${field} is invalid`);
  }
  return date.toISOString();
}

function safeNonNegativeInteger(value: unknown): number {
  const numeric = Number(value ?? 0);
  if (!Number.isFinite(numeric) || numeric < 0) return 0;
  return Math.floor(numeric);
}

function safeNonNegativeNumber(value: unknown): number {
  const numeric = Number(value ?? 0);
  if (!Number.isFinite(numeric) || numeric < 0) return 0;
  return numeric;
}

function fromTurnRow(row: Record<string, unknown>): TurnRecord {
  return {
    conversationId: String(row["conversation_id"]),
    turnIndex: Number(row["turn_index"]),
    role: String(row["role"]) as TurnRole,
    content: row["content"],
    model: row["model"] ? String(row["model"]) : null,
    tokensIn: Number(row["tokens_in"] ?? 0),
    tokensOut: Number(row["tokens_out"] ?? 0),
    costUsd: Number(row["cost_usd"] ?? 0),
    latencyMs: Number(row["latency_ms"] ?? 0),
    createdAt: toIso(row["created_at"]),
  };
}

function toIso(value: unknown): string {
  if (value instanceof Date) return value.toISOString();
  if (typeof value === "string") return new Date(value).toISOString();
  return new Date().toISOString();
}

export const conversationStoreInternals = {
  DEFAULT_SAVED_CHAT_TTL_DAYS,
  MAX_SAVED_CHAT_TITLE_LENGTH,
  coerceTtlDays,
};

import test from "node:test";
import assert from "node:assert/strict";

import {
  ConversationStoreError,
  archiveSavedConversation,
  createSavedConversation,
  conversationStoreInternals,
  listSavedDashboardConversations,
  loadConversationForUser,
  renameSavedConversation,
  type ConversationStoreDeps,
} from "./conversationStore.js";

interface QueryCall {
  sql: string;
  params: unknown[];
}

function makeDeps(rowsByCall: unknown[][], featureValues: unknown[] = []): ConversationStoreDeps & { calls: QueryCall[] } {
  const calls: QueryCall[] = [];
  return {
    calls,
    databaseConfigured: () => true,
    now: () => new Date("2026-05-10T12:00:00.000Z"),
    idFactory: () => "conv_test",
    featureValueProvider: async <T>() => featureValues.shift() as T | undefined,
    dataSourceProvider: async () => ({
      async query<T = unknown>(sql: string, params: unknown[]): Promise<T> {
        calls.push({ sql, params });
        return (rowsByCall.shift() ?? []) as T;
      },
      async transaction<T>(run: (manager: { query<TQuery = unknown>(sql: string, params: unknown[]): Promise<TQuery> }) => Promise<T>): Promise<T> {
        return run({
          async query<TQuery = unknown>(sql: string, params: unknown[]): Promise<TQuery> {
            calls.push({ sql, params });
            return (rowsByCall.shift() ?? []) as TQuery;
          },
        });
      },
    }),
  };
}

const baseRow = {
  id: "conv_a",
  user_id: "user_a",
  channel: "dashboard",
  title: "Daily thesis",
  started_at: new Date("2026-05-10T12:00:00.000Z"),
  updated_at: new Date("2026-05-10T12:00:00.000Z"),
  archived_at: null,
  expires_at: new Date("2026-05-17T12:00:00.000Z"),
  ended_at: null,
  turn_count: 0,
  total_tokens_in: 0,
  total_tokens_out: 0,
  total_cost_usd: "0",
  termination_reason: null,
  tool_call_count: 0,
  model: "test-model",
};

test("createSavedConversation applies the default 7 day TTL when no override is configured", async () => {
  const deps = makeDeps([[baseRow]], [undefined]);

  const created = await createSavedConversation({ userId: "user_a", title: " Daily thesis ", model: "test-model" }, deps);

  assert.equal(created.id, "conv_a");
  assert.equal(created.title, "Daily thesis");
  assert.equal(created.expiresAt, "2026-05-17T12:00:00.000Z");
  assert.match(deps.calls[0]!.sql, /INSERT INTO conversations/);
  assert.deepEqual(deps.calls[0]!.params.slice(0, 6), [
    "conv_test",
    "user_a",
    "dashboard",
    "test-model",
    "Daily thesis",
    new Date("2026-05-17T12:00:00.000Z"),
  ]);
});

test("createSavedConversation honors positive TTL overrides and coerces invalid or low values back to seven days", async () => {
  const valid = makeDeps([[{ ...baseRow, id: "conv_valid", expires_at: new Date("2026-05-13T12:00:00.000Z") }]], [3]);
  const validCreated = await createSavedConversation({ userId: "user_a" }, valid);
  assert.equal(validCreated.expiresAt, "2026-05-13T12:00:00.000Z");
  assert.deepEqual(valid.calls[0]!.params.slice(4, 6), [null, new Date("2026-05-13T12:00:00.000Z")]);

  for (const invalidValue of [0, -1, "abc", Number.NaN]) {
    const deps = makeDeps([[baseRow]], [invalidValue]);
    await createSavedConversation({ userId: "user_a" }, deps);
    assert.deepEqual(deps.calls[0]!.params.slice(4, 6), [null, new Date("2026-05-17T12:00:00.000Z")]);
  }
});

test("listSavedDashboardConversations returns only dashboard conversations scoped to the requested user and excludes archived rows in SQL", async () => {
  const deps = makeDeps([[baseRow]]);

  const list = await listSavedDashboardConversations("user_a", deps);

  assert.equal(list.length, 1);
  assert.equal(list[0]!.userId, "user_a");
  assert.equal(list[0]!.turnCount, 0);
  assert.match(deps.calls[0]!.sql, /WHERE user_id = \$1/);
  assert.match(deps.calls[0]!.sql, /channel = 'dashboard'/);
  assert.match(deps.calls[0]!.sql, /archived_at IS NULL/);
  assert.match(deps.calls[0]!.sql, /ORDER BY updated_at DESC, started_at DESC/);
  assert.deepEqual(deps.calls[0]!.params, ["user_a"]);
});

test("loadConversationForUser reports active archived expired and missing conversation states without leaking other users", async () => {
  const activeDeps = makeDeps([[baseRow]]);
  const active = await loadConversationForUser({ userId: "user_a", conversationId: "conv_a" }, activeDeps);
  assert.equal(active?.accessState, "active");
  assert.equal(active?.isExpired, false);
  assert.deepEqual(activeDeps.calls[0]!.params, ["conv_a", "user_a"]);

  const archivedDeps = makeDeps([[{ ...baseRow, archived_at: new Date("2026-05-11T00:00:00.000Z") }]]);
  const archived = await loadConversationForUser({ userId: "user_a", conversationId: "conv_a" }, archivedDeps);
  assert.equal(archived?.accessState, "archived");

  const expiredDeps = makeDeps([[{ ...baseRow, expires_at: new Date("2026-05-09T00:00:00.000Z") }]]);
  const expired = await loadConversationForUser({ userId: "user_a", conversationId: "conv_a" }, expiredDeps);
  assert.equal(expired?.accessState, "expired");

  const missingDeps = makeDeps([[]]);
  assert.equal(await loadConversationForUser({ userId: "user_b", conversationId: "conv_a" }, missingDeps), null);
});

test("renameSavedConversation validates titles and updates only a matching active conversation owned by the user", async () => {
  const deps = makeDeps([[{ ...baseRow, title: "Renamed" }]]);

  const renamed = await renameSavedConversation({ userId: "user_a", conversationId: "conv_a", title: " Renamed " }, deps);

  assert.equal(renamed.title, "Renamed");
  assert.match(deps.calls[0]!.sql, /UPDATE conversations/);
  assert.match(deps.calls[0]!.sql, /WHERE id = \$2 AND user_id = \$3/);
  assert.match(deps.calls[0]!.sql, /archived_at IS NULL/);
  assert.deepEqual(deps.calls[0]!.params, ["Renamed", "conv_a", "user_a"]);

  for (const title of ["", "   ", "x".repeat(conversationStoreInternals.MAX_SAVED_CHAT_TITLE_LENGTH + 1)]) {
    await assert.rejects(
      () => renameSavedConversation({ userId: "user_a", conversationId: "conv_a", title }, makeDeps([])),
      (error: unknown) => error instanceof ConversationStoreError && error.code === "INVALID_TITLE"
    );
  }
});

test("rename and archive fail closed for missing or wrong-user conversations", async () => {
  await assert.rejects(
